import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';

export default function BackerDashboard() {
  const { user } = useAuth();
  const [contributions, setContributions] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    axios.get('/api/contributions/my')
      .then(r => setContributions(r.data))
      .catch(console.error)
      .finally(() => setLoading(false));
  }, []);

  const totalContributed = contributions.reduce((sum, c) => sum + c.amount, 0);

  return (
    <div style={{ background: '#0a0d1a', minHeight: '100vh' }} className="px-6 py-10">
      <div className="max-w-4xl mx-auto">
        <div className="mb-10">
          <h1 style={{ fontFamily: 'Syne, sans-serif' }} className="text-3xl font-bold">My Portfolio</h1>
          <p className="text-gray-400 mt-1">Welcome back, {user.name}</p>
        </div>

        {/* Stats */}
        <div className="grid grid-cols-3 gap-4 mb-10">
          {[
            { label: 'Total Invested', value: `$${totalContributed.toLocaleString()}`, color: '#00d4aa' },
            { label: 'Projects Backed', value: new Set(contributions.map(c => c.project?._id)).size, color: '#8b5cf6' },
            { label: 'Contributions', value: contributions.length, color: '#f59e0b' },
          ].map(s => (
            <div key={s.label} style={{ background: '#111827', border: '1px solid #1f2937' }}
                 className="p-6 rounded-2xl text-center">
              <div style={{ color: s.color, fontFamily: 'Syne, sans-serif' }} className="text-3xl font-black mb-1">{s.value}</div>
              <div className="text-gray-400 text-sm">{s.label}</div>
            </div>
          ))}
        </div>

        <div className="flex items-center justify-between mb-6">
          <h2 className="font-bold text-xl">Contribution History</h2>
          <Link to="/projects"
            style={{ background: '#00d4aa', color: '#0a0d1a' }}
            className="px-5 py-2 rounded-xl font-bold text-sm hover:opacity-90 transition-all">
            Browse Projects
          </Link>
        </div>

        {loading ? (
          <div className="text-center text-gray-500 py-20">Loading...</div>
        ) : contributions.length === 0 ? (
          <div style={{ border: '1px dashed #374151' }} className="rounded-2xl p-16 text-center">
            <div className="text-4xl mb-4">💰</div>
            <h2 className="text-xl font-semibold mb-2">No contributions yet</h2>
            <p className="text-gray-400 mb-6 text-sm">Start backing innovative projects today</p>
            <Link to="/projects"
              style={{ background: '#00d4aa', color: '#0a0d1a' }}
              className="px-6 py-2.5 rounded-xl font-bold text-sm inline-block">
              Browse Projects
            </Link>
          </div>
        ) : (
          <div className="space-y-3">
            {contributions.map(c => (
              <div key={c._id} style={{ background: '#111827', border: '1px solid #1f2937' }}
                   className="rounded-xl p-5 flex items-center justify-between">
                <div>
                  <Link to={`/projects/${c.project?._id}`}
                        className="font-semibold hover:text-teal-400 transition-colors">
                    {c.project?.title || 'Project'}
                  </Link>
                  <div className="flex gap-3 text-xs text-gray-500 mt-1">
                    <span>{c.project?.category}</span>
                    <span>·</span>
                    <span>TXN: {c.transactionId}</span>
                    <span>·</span>
                    <span>{new Date(c.createdAt).toLocaleDateString()}</span>
                  </div>
                  {c.message && <p className="text-gray-400 text-sm mt-2">"{c.message}"</p>}
                </div>
                <div className="text-right">
                  <div style={{ color: '#00d4aa', fontFamily: 'Syne, sans-serif' }}
                       className="text-2xl font-black">+${c.amount.toLocaleString()}</div>
                  <div style={{ color: '#10b981' }} className="text-xs mt-0.5">✓ {c.status}</div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
